49	            LuaValue::Str(s) => format!("{}: {}", e_tag(e), String::from_utf8_lossy(s.as_bytes())),
50	            other => format!("{}: {:?}", e_tag(e), other),
51	        },
52	        LuaError::Memory | LuaError::Error | LuaError::Yield
53	        | LuaError::File | LuaError::Gc => format!("{}", e_tag(e)),
