81	        state.global_mut().parser_hook = Some(parser_hook);
82	
83	        eprintln!("[2/4] Opening standard library...");
84	        open_libs(&mut state).map_err(|e| format!("open_libs failed: {}", render_lua_error(&e)))?;
85	
86	        eprintln!("[3/4] Loading source (parse + compile)...");
