91	                Ok(Some(s)) => String::from_utf8_lossy(s.as_bytes()).into_owned(),
92	                _ => "(no error message on stack)".to_string(),
93	            };
94	            return Err(format!(
95	                "Syntax: {} (load_string status={})",
96	                msg, status
97	            ));
98	        }
99	
100	        eprintln!("[4/4] Executing chunk...");
101	        let final_status = pcall_k(&mut state, 0, MULTRET, 0, 0, None)
102	            .map_err(|e| format!("pcall_k failed: {}", render_lua_error(&e)))?;
103	
104	        Ok::<_, String>(final_status)
