113	            eprintln!("[err] {}", msg);
114	            ExitCode::from(1)
115	        }
116	        Err(panic) => {
117	            let msg = if let Some(s) = panic.downcast_ref::<String>() {
118	                s.clone()
119	            } else if let Some(s) = panic.downcast_ref::<&str>() {
