602	/// Ensure the stack has at least `space` extra slots; raise on failure.
603	///
604	/// C: `LUALIB_API void luaL_checkstack(lua_State *L, int space, const char *msg)`
605	pub fn check_stack(
606	    state: &mut LuaState,
607	    space: i32,
608	    msg: Option<&[u8]>,
609	) -> Result<(), LuaError> {
610	    // C: if (l_unlikely(!lua_checkstack(L, space)))
611	    if !state.check_stack_space(space) {
612	        match msg {
613	            Some(m) => {
614	                return Err(LuaError::runtime(format_args!(
615	                    "stack overflow ({})",
616	                    BStr(m)
617	                )));
618	            }
619	            None => {
620	                return Err(LuaError::runtime(format_args!("stack overflow")));
621	            }
622	        }
623	    }
624	    Ok(())
625	}
