665	/// C: `LUALIB_API const char *luaL_optlstring(lua_State *L, int arg, const char *def, size_t *len)`
666	pub fn opt_lstring(
667	    state: &mut LuaState,
668	    arg: i32,
669	    def: Option<&[u8]>,
670	) -> Result<Option<Vec<u8>>, LuaError> {
