751	impl LuaBuffer {
752	    /// Create a new empty buffer.
753	    ///
754	    /// C: the initial `luaL_Buffer` has a small inline array of `LUAL_BUFFERSIZE` bytes.
755	    /// Rust uses `Vec::new()` which starts at zero capacity; capacity is managed by Vec.
756	    pub fn new() -> Self {
757	        LuaBuffer { data: Vec::new() }
758	    }
