1206	/// Register the functions in `l` into the table at `-(nup + 1)`, giving each
1207	/// closure the `nup` upvalues currently at the top of the stack.
1208	///
1209	/// C: `LUALIB_API void luaL_setfuncs(lua_State *L, const luaL_Reg *l, int nup)`
1210	pub fn set_funcs(
1211	    state: &mut LuaState,
1212	    l: &[LuaReg],
1213	    nup: i32,
1214	) -> Result<(), LuaError> {
1215	    check_stack(state, nup, Some(b"too many upvalues"))?;
1216	    for reg in l {
1217	        match reg.func {
1218	            None => {
1219	                // C: lua_pushboolean(L, 0);
1220	                state.push(LuaValue::Bool(false));
1221	            }
1222	            Some(f) => {
1223	                // C: for (i = 0; i < nup; i++) lua_pushvalue(L, -nup);
1224	                for _ in 0..nup {
1225	                    state.push_value(-nup)?;
1226	                }
1227	                // C: lua_pushcclosure(L, l->func, nup);
1228	                state.push_c_closure(f, nup)?;
1229	            }
1230	        }
1231	        // C: lua_setfield(L, -(nup + 2), l->name);
1232	        state.set_field(-(nup + 2), reg.name)?;
1233	    }
1234	    // C: lua_pop(L, nup);
1235	    state.pop_n(nup as usize);
1236	    Ok(())
1237	}
