// C: RESERVED enum from llex.h; FIRST_RESERVED = 257 (UCHAR_MAX + 1).
// TODO(port): replace with lua_lex::TokenKind enum when lua-lex lands.

pub type TokenKind = i32;
pub const TK_AND: TokenKind = 257;
